class Solution:
    def rob(self, root: Optional[TreeNode]) -> int:
        def dfs(node):
            if not node: return (0, 0)
            lr, ln = dfs(node.left)
            rr, rn = dfs(node.right)
            rob = node.val + ln + rn
            not_rob = max(lr, ln) + max(rr, rn)
            return rob, not_rob
        return max(dfs(root))

