class Solution {
    pair<long long,long long> dfs(TreeNode* node) {
        if (!node) return {0,0};
        auto [lr, ln] = dfs(node->left);
        auto [rr, rn] = dfs(node->right);
        long long rob = node->val + ln + rn;
        long long notRob = max(lr, ln) + max(rr, rn);
        return {rob, notRob};
    }
public:
    int rob(TreeNode* root) {
        auto [a,b] = dfs(root);
        return max(a,b);
    }
};

