static long long pairRob(TreeNode* node, int take) {
    if (!node) return 0;
    /* simplified: returns max for subtree */
    long long left0 = pairRob(node->left, 0), left1 = pairRob(node->left, 1);
    long long right0 = pairRob(node->right, 0), right1 = pairRob(node->right, 1);
    if (take) return node->val + left0 + right0;
    return (left0 > left1 ? left0 : left1) + (right0 > right1 ? right0 : right1);
}
int rob(TreeNode* root) {
    long long a = pairRob(root, 0), b = pairRob(root, 1);
    return (int)(a > b ? a : b);
}
